import Ariadne
from ariadne import QueryType, MutationType, ObjectType, Field
from graphql import GraphQLResolveInfo

# Define the User and Post types
User = ObjectType("User", {
    "id": Field(GraphQLID),
    "username": Field(GraphQLString),
    "bio": Field(GraphQLString),
    "email": Field(GraphQLString, private=True),
    "phone": Field(GraphQLString, private=True),
    "address": Field(GraphQLString, private=True)
})

Post = ObjectType("Post", {
    "id": Field(GraphQLID),
    "title": Field(GraphQLString),
    "content": Field(GraphQLString),
    "author": Field(User)
})

# Define the query to fetch user profiles
query = QueryType({
    "user": Field(User, {
        "id": GraphQLID
    })
})

# Define the mutation to create a new post
mutation = MutationType({
    "createPost": Field(Post, {
        "title": GraphQLString,
        "content": GraphQLString
    })
})

# Define the resolvers for the query and mutation
def resolve_user(parent, info: GraphQLResolveInfo):
    # Get the current user from the middleware
    current_user = info.context["current_user"]

    # Return the user with the given ID
    return User(id=current_user.id)

def resolve_create_post(parent, args: dict, info: GraphQLResolveInfo):
    # Get the current user from the middleware
    current_user = info.context["current_user"]

    # Create a new post with the given title and content
    post = Post(title=args["title"], content=args["content"], author=current_user)

    # Return the newly created post
    return post

# Define the schema for the GraphQL API
schema = Ariadne.Schema(query, mutation)